import type { FC } from 'react';
import React from 'react';
import type { GenerateConfig } from '../generate';
import PickerPanel from '../Comp/PickerPanel';
import type { MODE, PickerPanelProps } from '..';

function generateInnerPanel<DateType>(generateConfig: GenerateConfig<DateType>) {
  const getPanel = (mode: MODE) => {
    const BasePanel: FC<PickerPanelProps<DateType>> = props => (
      <PickerPanel {...props} generateConfig={generateConfig} mode={mode} />
    );
    return BasePanel;
  };

  const TimePanel = getPanel('time');
  const TimeCombinePanel = getPanel('timeCombine');

  return {
    TimePanel,
    TimeCombinePanel,
  };
}

export default function generatePicker<DateType>(generateConfig: GenerateConfig<DateType>) {
  const { TimePanel, TimeCombinePanel } = generateInnerPanel(generateConfig);
  const MergedPanel = {
    TimePanel,
    TimeCombinePanel,
  };

  return MergedPanel;
}
